update public.faculties set source_id = coalesce(source_id, 'sdd_ubids_business_and_management_studies') where source_id = 'sdd_ubids_business_and_management_studies' or (name = 'Business and Management Studies' and university_id = (select id from public.universities where source_id = 'sdd_ubids'));
